<template>
  <div class="pt-4 lg:pt-12 w-full px-0.5 md:px-4 text-center">
    <div 
      class="relative flex flex-col min-w-0 break-words bg-white w-full mb-8 shadow-2xl rounded-lg card"
      :class="{ 'is-flipped': flipped }" 
      @click="toggleFlip" 
      @keyup.enter.space.prevent="toggleFlip" 
      tabindex="0"
      role="button"
    >
      <div class="card-inner flex-auto">

        <div class="card-front absolute inset-0 flex flex-col items-center justify-start px-4 py-6">
          <div :class="['flex items-center justify-center w-12 h-12 mb-4 rounded-full shadow-lg shrink-0', iconBgClass]">
            <i :class="['fa-solid', frontIcon, 'fa-xl', 'text-white']"></i>
          </div>

          <h6 class="text-2xl lg:text-2xl font-semibold text-center w-full leading-tight mb-1">{{ frontTitle }}</h6>

          <div class="flex-1 w-full flex flex-col items-center justify-start py-4 gap-2">
            <p v-if="frontText" class="text-lg lg:text-xl font-medium leading-relaxed mb-4 text-blueGray-500">
              {{ frontText }}
            </p>

            <div v-if="features && features.length" class="flex flex-col items-center w-full gap-2 mt-8">
              <span v-for="(f, i) in features" :key="i"
                class="px-3 py-4 bg-gray-50 rounded-full text-lg lg:text-xl text-gray-700 w-full">
                {{ f }}
              </span>
