          </button>
        </div>

        <div class="card-back absolute inset-0 flex flex-col items-center justify-start px-4 py-6">
          
          <button 
            @click.stop="toggleFlip" 
            class="absolute top-4 right-4 text-blueGray-400 hover:text-blueGray-600 transition-colors z-10"
            :title="$t('flipCards.backReturn')"
          >
            <i class="fa-solid fa-circle-xmark fa-xl"></i>
          </button>

          <div class="flex-1 w-full overflow-y-auto custom-scrollbar pt-6">
            <div v-if="backTextComputed"
              class="text-base lg:text-lg text-blueGray-600 space-y-2 text-left w-full leading-snug back-content">
              <div v-html="backTextComputed"></div>
            </div>
          </div>

          <div class="flex flex-col sm:flex-row gap-2 mt-4 w-full justify-center">
            <router-link 
              v-if="backLink" 
              :to="backLink" 
              @click.stop
              :class="['inline-block px-6 py-2 text-base font-bold text-white rounded-lg tracking-wide transition shrink-0 shadow hover:scale-105', iconBgClass]"
            >
              {{ backCta || $t('flipCards.backCta') }}
            </router-link>
            
            <button 
              @click.stop="toggleFlip"
              class="px-6 py-2 text-base font-bold text-blueGray-500 bg-blueGray-100 rounded-lg tracking-wide hover:bg-blueGray-200 transition"
            >
              {{ $t('flipCards.backReturn') }}
            </button>
          </div>
        </div>

      </div>
    </div>
  </div>
</template>

<script>
export default {
  name: "FlipCard",
  props: {
    frontIcon: { type: String, default: "fa-laptop-code" },
    iconBgClass: { type: String, default: "bg-teal-500" },
    frontTitle: { type: String, required: true },
    frontText: { type: String, default: "" },
    features: { type: Array, default: () => [] },
    frontLink: { type: [String, Object], default: null },
    frontCta: { type: String, default: null },
    backText: { type: String, default: "" },
    backLink: { type: [String, Object], default: null },
    backCta: { type: String, default: null }
  },
  data() {
    return { flipped: false };
  },
  methods: {
    toggleFlip() {
      this.flipped = !this.flipped;
    }
  },
  computed: {
    backTextComputed() {
      return this.backText;
    }
  }
};
</script>

