<template>
  <nav class="top-0 fixed z-50 w-full flex flex-wrap items-center justify-between px-2 py-3 navbar-expand-lg"
    style="background-color: rgba(0,0,0,0.6); backdrop-filter: blur(8px);">
    <div class="container px-4 mx-auto flex flex-wrap items-center justify-between">

      <div class="w-full relative flex justify-between lg:w-auto lg:static lg:block lg:justify-start">
        <div class="flex items-center">
          <img src="/images/logo_tr6.png" alt="Logo Equaiar"
            class="h-10 lg:h-20 w-auto mix-blend-difference transition-all duration-300" />
          <router-link to="/"
            style="font-family: 'Plus Jakarta Sans', sans-serif; font-weight: 500; letter-spacing: 0.09em; margin-left: 15px;"
            class="text-white text-2xl lg:text-5xl xl:text-6xl transition-all duration-300">
            EQUAIAR
          </router-link>
        </div>

        <button
          class="cursor-pointer text-xl leading-none px-3 py-1 border border-solid border-transparent rounded bg-transparent block lg:hidden outline-none focus:outline-none"
          type="button" @click="setNavbarOpen">
          <i class="text-white fas fa-bars"></i>
        </button>
      </div>

      <div class="lg:flex flex-grow items-center lg:bg-transparent lg:shadow-none transition-all duration-300"
        :class="[navbarOpen ? 'block bg-black bg-opacity-95 p-4 rounded-lg mt-2' : 'hidden']">

        <ul class="flex flex-col lg:flex-row list-none lg:ml-auto">

          <li class="flex items-center">
            <router-link to="/Sobre_Nosotros" @click="closeNavbar"
              class="text-white hover:text-blueGray-300 px-3 py-4 lg:py-2 text-base uppercase font-bold w-full text-left">
              {{ $t('nav.about') }}
            </router-link>
          </li>

          <li class="flex items-center">
            <a href="#rubros" @click.prevent="goToRubros"
              class="text-white hover:text-blueGray-300 px-3 py-4 lg:py-2 flex items-center text-base uppercase font-bold w-full text-left">
              {{ $t('nav.sectors') }}
            </a>
          </li>

          <li class="flex items-center">
            <router-link to="/Contacto" @click="closeNavbar"
              class="text-white hover:text-blueGray-300 px-3 py-4 lg:py-2 flex items-center text-base uppercase font-bold w-full text-left">
              {{ $t('nav.contact') }}
            </router-link>
          </li>

          <li class="flex items-center gap-1 px-3 py-2">
            <button @click="$i18n.locale = 'es'"
              :class="$i18n.locale === 'es' ? 'text-white font-bold' : 'text-blueGray-400'"
              class="text-sm uppercase hover:text-white transition">
              ES
            </button>
            <span class="text-blueGray-400">|</span>
            <button @click="$i18n.locale = 'en'"
              :class="$i18n.locale === 'en' ? 'text-white font-bold' : 'text-blueGray-400'"
              class="text-sm uppercase hover:text-white transition">
              EN
            </button>
          </li>

        </ul>
      </div>
    </div>
  </nav>
</template>

<script>
export default {
  data() {
    return {
      navbarOpen: false,
    };
  },
  methods: {
    setNavbarOpen() {
      this.navbarOpen = !this.navbarOpen;
    },
    // Nueva función para que el menú se cierre al tocar una opción
    closeNavbar() {
      this.navbarOpen = false;
    },
    // Función para hacer scroll suave a la sección de rubros    
    goToRubros() {
      this.closeNavbar();
      if (this.$route.path !== '/') {
        this.$router.push('/').then(() => {
          this.$nextTick(() => {
            setTimeout(() => {
              const el = document.getElementById('rubros');
              if (el) {
                const top = el.getBoundingClientRect().top + window.scrollY - 100;
                window.scrollTo({ top, behavior: 'smooth' });
              }
            }, 300); // tiempo para que el componente Landing monte
          });
        });
      } else {
        const el = document.getElementById('rubros');
        if (el) {
          const top = el.getBoundingClientRect().top + window.scrollY - 100;
          window.scrollTo({ top, behavior: 'smooth' });
        }
      }
    }
  },
};
</script>

<style scoped>
/* Optimizamos para que los links ocupen todo el ancho en móvil y sean fáciles de tocar */
@media (max-width: 1023px) {
  ul li {
    border-bottom: 1px solid rgba(255, 255, 255, 0.1);
  }

  ul li:last-child {
    border-bottom: none;
  }
}

/* Mantenemos tu estilo de tipografía */
.text-white {
  color: white !important;
}
</style>