<script>

import Navbar from "@/components/Navbars/AuthNavbar.vue";
import FooterComponent from "@/components/Footers/Footer.vue";
import FlipCard from "@/components/FlipCard.vue";
import WordCloudSphere from "@/components/WordCloudSphere.vue";
import LogoCarousel from "@/components/LogoCarousel.vue";
//SEO
import { useHead } from '@unhead/vue';

export default {
  components: {
    Navbar,
    FooterComponent,
    FlipCard,
    WordCloudSphere,
    LogoCarousel,
  },

  created() {
    useHead({
      title: 'EQUAIAR | Infraestructura, software y procesamiento de datos',
      meta: [
        { name: 'description', content: 'Somos una empresa argentina de tecnología, integrada por científicos y profesionales en software, infraestructura de cómputo e ingeniería de datos.' },
        { property: 'og:title', content: 'EQUAIAR | Infraestructura, software y procesamiento de datos' },
        { property: 'og:description', content: 'Somos una empresa argentina de tecnología, integrada por científicos y profesionales en software, infraestructura de cómputo e ingeniería de datos.' },
        { property: 'og:url', content: 'https://equaiar.com.ar/' },
        { property: 'og:image', content: 'https://equaiar.com.ar/images/fondoLanding.jpg' },
        { name: 'twitter:card', content: 'summary_large_image' },
      ],
      link: [
        { rel: 'canonical', href: 'https://equaiar.com.ar/' }
      ]
    })
  },

  data() {
    return {
      currentSlide: 0,
      intervalId: null,
      logos: [
        { src: "/logos/logo3.png", url: "https://impam.conicet.gov.ar/limra/" },
        { src: "/logos/logo4.png", url: "https://impam.conicet.gov.ar/" },
        { src: "/logos/logo5.png", url: "https://bioinfo.fmed.uba.ar/" },
      ],
    };
  },

  computed: {
    // Los slides se leen reactivamente desde i18n,
    // cambian automáticamente al cambiar de idioma
    slides() {
      return this.$tm('slides');
    },
  },

  mounted() {
    this.startAutoSlide();
  },

  beforeUnmount() {
    clearInterval(this.intervalId);
  },

  methods: {
    nextSlide() {
      this.currentSlide = (this.currentSlide + 1) % this.slides.length;
      this.resetAutoSlide();
    },
    prevSlide() {
      this.currentSlide = (this.currentSlide - 1 + this.slides.length) % this.slides.length;
      this.resetAutoSlide();
    },
    startAutoSlide() {
      this.intervalId = setInterval(() => {
        this.currentSlide = (this.currentSlide + 1) % this.slides.length;
      }, 10000);
    },
    resetAutoSlide() {
      clearInterval(this.intervalId);
      this.startAutoSlide();
    },
  },
};
</script>

