import { createApp } from "vue";
import { createWebHistory, createRouter } from "vue-router";
import { createI18n } from "vue-i18n";
import { createHead } from '@unhead/vue';
import './assets/styles/index.css';

// styles
import "@fortawesome/fontawesome-free/css/all.min.css";
import "@/assets/styles/tailwind.css";

// i18n
import es from "./locales/es.json";
import en from "./locales/en.json";

// views
import App from "@/App.vue";
import Landing from "@/views/Landing.vue";
import Sobre_Nosotros from "@/views/Sobre_Nosotros.vue";
import Contacto from "@/views/Contacto.vue";
import Servicios_bioinformaticos from "@/views/Servicios_bioinformaticos.vue";

// routes
const routes = [
  { path: "/", component: Landing },
  { path: "/Sobre_Nosotros", component: Sobre_Nosotros },
  { path: "/Contacto", component: Contacto },
  { path: "/Servicios_bioinformaticos", component: Servicios_bioinformaticos },
  { path: "/:pathMatch(.*)*", redirect: "/" },
];

const router = createRouter({
  history: createWebHistory(),
  routes,
  scrollBehavior(to) {
    if (to.hash === '#rubros') {
      return { el: to.hash, top: 100, behavior: 'smooth' }
    }
    if (to.hash) {
      return { el: to.hash, behavior: 'smooth' }
    }
    return { top: 0 }
  }
});

const i18n = createI18n({
  legacy: true,
  locale: 'es',
  fallbackLocale: 'en',
  warnHtmlMessage: false,
  messages: { es, en }
});

const head = createHead();

createApp(App).use(router).use(i18n).use(head).mount("#app");