<template>
  <div ref="root" class="lc-root" @mouseenter="pause" @mouseleave="play">
    <div class="lc-track">
      <transition-group v-if="isMobile" name="logo-fade" tag="div" class="lc-track-inner">
        <div v-for="logo in visibleLogos" :key="logo.src" class="lc-item">
          <a :href="logo.url" target="_blank" rel="noopener">
            <img :src="logo.src" alt="logo" @error="onImgError" />
          </a>
        </div>
      </transition-group>

      <div v-else class="lc-track-inner">
        <div v-for="logo in visibleLogos" :key="logo.src" class="lc-item">
          <a :href="logo.url" target="_blank" rel="noopener">
            <img :src="logo.src" alt="logo" @error="onImgError" />
          </a>
        </div>
      </div>
    </div>
  </div>
</template>

<script>
export default {
  name: "LogoCarousel",
  props: {
    logos: { type: Array, required: true },
    interval: { type: Number, default: 3000 },
    placeholder: { type: String, default: "/logos/placeholder.png" }
  },
  data() {
    return {
      current: 0,
      intervalId: null,
      isVisible: false,
      isMobile: false
    };
  },
  computed: {
    visibleLogos() {
      if (!this.logos || this.logos.length === 0) return [];
      const t = this.logos.length;
      const c = this.current;

      if (this.isMobile) {
        return [this.logos[c % t]];
      }

      return [
        this.logos[(c - 1 + t) % t],
        this.logos[c % t],
        this.logos[(c + 1) % t]
      ];
    }
  },
  methods: {
    step() {
      this.current = (this.current + 1) % this.logos.length;
    },
    play() {
      if (this.intervalId || !this.isVisible) return;
      this.intervalId = setInterval(this.step, this.interval);
    },
    pause() {
      if (!this.intervalId) return;
      clearInterval(this.intervalId);
      this.intervalId = null;
    },
    onImgError(e) {
      e.target.src = this.placeholder;
    },
    checkMobile() {
      this.isMobile = window.innerWidth < 768;
    },
    observeVisibility() {
      const observer = new IntersectionObserver(
        entries => {
          const entry = entries[0];
          this.isVisible = entry.isIntersecting;
          if (this.isVisible) this.play();
          else this.pause();
        },
        { threshold: 0.2 }
      );
      if (this.$refs.root) observer.observe(this.$refs.root);
    }
  },
  mounted() {
    this.checkMobile();
    window.addEventListener('resize', this.checkMobile);
    this.observeVisibility();
  },
  beforeUnmount() {
    window.removeEventListener('resize', this.checkMobile);
    this.pause();
  }
};
</script>

