<script setup>
import { onMounted, onUnmounted, ref, watch } from "vue";
import { useI18n } from "vue-i18n";  

const { t, locale } = useI18n();   
const canvasRef = ref(null);

const initTagCanvas = () => {
  if (!window.TagCanvas) return;

  try {
    const containerWidth = window.innerWidth;
    let size = 500;
    let fontSize = 18;

    if (containerWidth < 640) {
      size = containerWidth - 40;
      fontSize = 15;
    } else if (containerWidth < 1024) {
      size = 420;
      fontSize = 16;
    }

    if (canvasRef.value) {
      canvasRef.value.width = size;
      canvasRef.value.height = size;
    }

    window.TagCanvas.Start("myCanvas", "tags", {
      textColour: "#334155",
      textHeight: fontSize,
      outlineMethod: "none",
      reverse: true,
      depth: 0.8,
      wheelZoom: false,
      maxSpeed: 0.015,      // Aumentamos un poco para que reaccione más rápido
      minSpeed: 0.003,   
      decel: 0.98,   // Inercia más larga; tarda más en frenar al soltar
      initial: [0.05, -0.05], // Dirección de giro inicial
      dragControl: true,   // Habilita el arrastre para móvil
      freezeActive: false, // NO se detiene al pasar el mouse
      freezeMaxSpeed: false, // Evita que la velocidad se bloquee en cero
      noSelect: true,      // Evita que se seleccione texto al hacer clic
      clickToFront: 0,
      fadeIn: 800,
      textFont: "'Plus Jakarta Sans', sans-serif",
    });
  } catch (e) {
    console.log("Reiniciando esfera...");
  }
};

// Reiniciar cuando cambie el idioma
watch(locale, () => {
  if (window.TagCanvas) {
    window.TagCanvas.Delete("myCanvas");
  }
  setTimeout(initTagCanvas, 100);
});

const handleResize = () => {
  if (window.TagCanvas) {
    window.TagCanvas.Delete("myCanvas");
    initTagCanvas();
  }
};

onMounted(() => {
  setTimeout(initTagCanvas, 200); // Un pequeño margen para asegurar carga
  window.addEventListener("resize", handleResize);
});

onUnmounted(() => {
  window.removeEventListener("resize", handleResize);
});
</script>

<template>
  <div class="sphere-wrapper w-full flex justify-center items-center overflow-hidden py-4">
    <canvas 
      ref="canvasRef" 
      id="myCanvas" 
      class="max-w-full h-auto cursor-grab active:cursor-grabbing"
    >
      <p>{{ t('wordCloud.canvasError') }}</p>
    </canvas>

    <div id="tags" style="display:none;">
      <ul>
        <li><a href="#" @click.prevent>{{ t('wordCloud.tags.bigData') }}</a></li>
        <li><a href="#" @click.prevent>{{ t('wordCloud.tags.dataPipelines') }}</a></li>
        <li><a href="#" @click.prevent>{{ t('wordCloud.tags.ia') }}</a></li>
        <li><a href="#" @click.prevent>{{ t('wordCloud.tags.ml') }}</a></li>
        <li><a href="#" @click.prevent>{{ t('wordCloud.tags.estadistica') }}</a></li>
        <li><a href="#" @click.prevent>{{ t('wordCloud.tags.probabilidad') }}</a></li>
        <li><a href="#" @click.prevent>{{ t('wordCloud.tags.basesdatos') }}</a></li>
        <li><a href="#" @click.prevent>{{ t('wordCloud.tags.etl') }}</a></li>
        <li><a href="#" @click.prevent>{{ t('wordCloud.tags.automatizacion') }}</a></li>
        <li><a href="#" @click.prevent>{{ t('wordCloud.tags.mineria') }}</a></li>
        <li><a href="#" @click.prevent>{{ t('wordCloud.tags.orquestacion') }}</a></li>
        <li><a href="#" @click.prevent>{{ t('wordCloud.tags.web') }}</a></li>
        <li><a href="#" @click.prevent>{{ t('wordCloud.tags.movil') }}</a></li>
        <li><a href="#" @click.prevent>{{ t('wordCloud.tags.arquitectura') }}</a></li>
        <li><a href="#" @click.prevent>{{ t('wordCloud.tags.distribuidos') }}</a></li>
        <li><a href="#" @click.prevent>{{ t('wordCloud.tags.dqm') }}</a></li>
        <li><a href="#" @click.prevent>{{ t('wordCloud.tags.predictivo') }}</a></li>
        <li><a href="#" @click.prevent>{{ t('wordCloud.tags.features') }}</a></li>
        <li><a href="#" @click.prevent>{{ t('wordCloud.tags.genomica') }}</a></li>
      </ul>
    </div>
  </div>
</template>

<style scoped>
.sphere-wrapper {
  max-width: 100vw;
  touch-action: pan-y;
}

#tags a {
  pointer-events: none;
